import React, { useState, useEffect } from "react";
import { Routes, Route } from "react-router-dom";
import "./App.css";
import Login from "./components/Login";
import Register from "./components/Register";
import Profile from "./components/Profile";
import Logo from "./assets/logo.jpeg";

import Pathology from "./components/Pathology";
import BloodBank from "./components/BloodBank";
import Consultancy from "./components/Consultancy";
import Medicine from "./components/Medicine";

import PathologyPage from "./components/PathologyPage";
import BloodBankPage from "./components/BloodBankPage";
import ConsultancyPage from "./components/ConsultancyPage";
import MedicinePage from "./components/MedicinePage";
import About from "./components/About";

function App() {
  const [showLogin, setShowLogin] = useState(false);
  const [showRegister, setShowRegister] = useState(false);
  const [user, setUser] = useState(null);
  const [currentSlide, setCurrentSlide] = useState(0);

  const slides = [
    require("./assets/hero-bg.png"),
    require("./assets/hero-bg-1.jpg"),
    require("./assets/hero-bg-2.jpg"),
  ];

  // Load user from localStorage
  useEffect(() => {
    const savedUser = localStorage.getItem("user");
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  // Auto-slide images
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % slides.length);
    }, 4000);
    return () => clearInterval(interval);
  }, [slides.length]);

  const handleAuthSuccess = (userData) => {
    setUser(userData);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem("token");
    localStorage.removeItem("user");
  };

  return (
    <div className="app">
      {/* ===== HEADER ===== */}
      <header className="header">
        <div className="logo-container">
          <img src={Logo} alt="HEALink Logo" className="logo" />
          <h1>HEALink</h1>
        </div>
        <nav>
          <ul>
            <li><a href="/" className="nav-link">Home</a></li>
            <li><a href="#about-section" className="nav-link">About</a></li>
            <li><a href="#help-section" className="nav-link">Help</a></li>
          </ul>
        </nav>
        <div className="auth-buttons">
          {user ? (
            <Profile user={user} onLogout={handleLogout} />
          ) : (
            <>
              <button className="login-btn" onClick={() => setShowLogin(true)}>Login</button>
              <button className="register-btn" onClick={() => setShowRegister(true)}>Register</button>
            </>
          )}
        </div>
      </header>

      {/* ===== ROUTES ===== */}
      <Routes>
        <Route
          path="/"
          element={
            <>
              {/* ===== HERO SECTION ===== */}
              <section className="hero">
                <div className="hero-content">
                  <h2>Your Health, Our Priority</h2>
                  <p>Connecting people to better healthcare solutions.</p>
                  <button
                    onClick={() =>
                      document.querySelector(".sections")
                        .scrollIntoView({ behavior: "smooth" })
                    }
                    className="get-started-btn"
                  >
                    Get Started
                  </button>
                </div>

                {/* Fading Image Slider */}
                <div className="hero-slider">
                  {slides.map((src, index) => (
                    <img
                      key={index}
                      src={src}
                      alt={`Slide ${index + 1}`}
                      className={`fade-slide ${index === currentSlide ? "active" : ""}`}
                    />
                  ))}
                </div>
              </section>

              <About />

              <section className="sections">
                <Pathology />
                <BloodBank />
                <Consultancy />
                <Medicine />
              </section>
            </>
          }
        />
        <Route path="/pathology" element={<PathologyPage />} />
        <Route path="/bloodbank" element={<BloodBankPage />} />
        <Route path="/consultancy" element={<ConsultancyPage />} />
        <Route path="/medicine" element={<MedicinePage />} />
      </Routes>

      {/* ===== FOOTER ===== */}
      <footer className="footer">
        <p>© 2025 HEALink. All rights reserved.</p>
      </footer>

      {/* ===== MODALS ===== */}
      {showLogin && (
        <Login
          onClose={() => setShowLogin(false)}
          onLoginSuccess={handleAuthSuccess}
        />
      )}
      {showRegister && (
        <Register
          onClose={() => setShowRegister(false)}
          onRegisterSuccess={handleAuthSuccess}
        />
      )}
    </div>
  );
}

export default App;
